use sceua::{minimize, Config};

let result = minimize(
    |x| x.iter().map(|v| v * v).sum::&lt;f64&gt;(),
    &[-5.0, -5.0],
    &[5.0, 5.0],
    Config::default(),
).unwrap();

println!("best = {:?}", result.best_x);
println!("value = {}", result.best_f);

The duan_test_func module exposes the seven benchmark functions from Duan’s Matlab SCE-UA suite (Goldstein-Price, Rosenbrock, Griewank, Shekel, Hartman, etc.). They can be used for validation or custom benchmarking:
use sceua::duan_test_func::rosenbrock;
assert_eq!(rosenbrock(&[1.0, 1.0]), 0.0);
